# Get price scale positions from TradingView chart via JS
result = js('''
(function() {
  const chart = document.querySelector(\"#chart-app\");
  if (!chart) return \"no chart\";
  const rect = chart.getBoundingClientRect();
  return JSON.stringify({
    width: rect.width,
    height: rect.height,
    top: rect.top,
    bottom: rect.bottom,
    right: rect.right
  });
})()
''')
